MERGE INTO CONSULTAS FIN USING (SELECT '800629PreviewCausacionRef' INFORME ,TO_CLOB(q'[SELECT
TEMP_DETALLE_COMPROBANTE_CNT.CONSECUTIVO, TEMP_DETALLE_COMPROBANTE_CNT.CUENTA, PLAN_CONTABLE.NOMBRE   NOMBREPLANCONTABLE,
TEMP_DETALLE_COMPROBANTE_CNT.VALOR_DEBITO, TEMP_DETALLE_COMPROBANTE_CNT.VALOR_CREDITO, TEMP_DETALLE_COMPROBANTE_CNT.BASE_GRAVABLE,
TEMP_DETALLE_COMPROBANTE_CNT.TERCERO,TEMP_DETALLE_COMPROBANTE_CNT.REFERENCIA, TEMP_DETALLE_COMPROBANTE_CNT.CENTRO_COSTO
FROM
    TEMP_DETALLE_COMPROBANTE_CNT
    LEFT JOIN PLAN_CONTABLE ON TEMP_DETALLE_COMPROBANTE_CNT.COMPANIA = PLAN_CONTABLE.COMPANIA
                          AND TEMP_DETALLE_COMPROBANTE_CNT.CUENTA = PLAN_CONTABLE.CODIGO
                          AND TEMP_DETALLE_COMPROBANTE_CNT.ANO = PLAN_CONTABLE.ANO
    WHERE TEMP_DETALLE_COMPROBANTE_CNT.COMPANIA = s$compania$s
AND TEMP_DETALLE_COMPROBANTE_CNT.ANO = s$ano$s
AND TEMP_DETALLE_COMPROBANTE_CNT.COMPROBANTE = s$numero$s
AND TEMP_DETALLE_COMPROBANTE_CNT.TIPO_CPTE = 's$tipo$s']') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, 'mrosero' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);